// ===============================================
// Validar parámetros (v3: lee de Google Sheets)
// ===============================================
var startDate = (msg.req && msg.req.query && msg.req.query.startDate || '').toString().trim();
var endDate = (msg.req && msg.req.query && msg.req.query.endDate || '').toString().trim();
var criticalThreshold = parseFloat(msg.req && msg.req.query && msg.req.query.criticalThreshold) || 10000000;

// Generar UUID
var uuid = (
  Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 6).toUpperCase() +
  Math.random().toString(36).substring(2, 6).toUpperCase()
);

// Default: mes actual
if (!startDate || !endDate) {
  var now = new Date();
  var y = now.getFullYear();
  var m = String(now.getMonth() + 1).padStart(2, '0');
  var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();
  startDate = y + m + '01';
  endDate = y + m + String(lastDay).padStart(2, '0');
}

// Validar formato
if (!/^\d{8}$/.test(startDate) || !/^\d{8}$/.test(endDate)) {
  msg.statusCode = 400;
  msg.payload = { error: 'Formato inválido. Use YYYYMMDD' };
  return msg;
}
if (endDate < startDate) {
  msg.statusCode = 400;
  msg.payload = { error: 'endDate debe ser >= startDate' };
  return msg;
}

// Guardar metadata para el transform
msg._trace = {
  uuid: uuid,
  startDate: startDate,
  endDate: endDate,
  criticalThreshold: criticalThreshold
};

// No preparamos query — el nodo GSheet lee todo el rango SumasSaldos!A2:I
// El filtro por fecha se hace en el transform (columna G = PERIODO)
node.warn('[SumasSaldos-v3] ' + uuid + ' periodo ' + startDate + '-' + endDate + ' (desde Google Sheets)');
return msg;

// ===============================================
// Transformar filas Google Sheets → formato dashboard
// Sheet columns: [0]CODIGO [1]CUENTA [2]RUBRO [3]DEBE [4]HABER [5]SALDO [6]PERIODO [7]FECHA_SYNC [8]UNIDAD_NEGOCIO
// ===============================================

if (msg.statusCode >= 400) { return msg; }

var rows = msg.payload;
var trace = msg._trace || {};
var startDate = (trace.startDate || '').toString();
var endDate = (trace.endDate || '').toString();
var criticalThreshold = trace.criticalThreshold || 10000000;

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[SumasSaldos-v3] Sheet sin datos');
  msg.payload = buildEmptyResponse(startDate, endDate, trace.uuid, 'Google Sheets sin datos. Ejecutar sync primero.');
  return msg;
}

node.warn('[SumasSaldos-v3] ' + rows.length + ' filas leidas del sheet');

// Mapear filas: filtrar por periodo y convertir a objetos
var sumasSaldos = [];
var periodoEsperado = startDate + '-' + endDate;

for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  if (!Array.isArray(r) || r.length < 6) continue;

  // Filtrar por PERIODO (col 6): incluir si el rango solicitado solapa con el periodo de la fila
  var filaPeriodo = (r[6] || '').toString().trim();
  if (startDate && endDate && filaPeriodo) {
    var partes = filaPeriodo.split('-');
    var filaStart = partes[0] || '00000000';
    var filaEnd = partes[1] || '99999999';
    // Excluir solo si NO hay solapamiento
    if (filaEnd < startDate || filaStart > endDate) continue;
  }

  var codigo = (r[0] || '').toString().trim();
  var cuenta = (r[1] || '').toString().trim();
  var rubro = (r[2] || '').toString().trim();
  var debe = parseFloat(r[3]) || 0;
  var haber = parseFloat(r[4]) || 0;
  var saldo = parseFloat(r[5]) || (debe - haber);
  var absSaldo = Math.abs(saldo);

  var estado = 'ok';
  if (absSaldo >= criticalThreshold) { estado = 'crit'; }
  else if (absSaldo >= criticalThreshold * 0.6) { estado = 'warn'; }

  sumasSaldos.push({
    codigo: codigo,
    cuenta: cuenta,
    rubro: rubro,
    debeAcum: debe,
    haberAcum: haber,
    saldo: saldo,
    variacion: 0,
    estado: estado,
    unidad: (r[8] || '').toString().trim()
  });
}

node.warn('[SumasSaldos-v3] ' + sumasSaldos.length + ' cuentas en el periodo ' + periodoEsperado);

// KPIs
var totalDebe = 0, totalHaber = 0, critCount = 0, warnCount = 0;
for (var i = 0; i < sumasSaldos.length; i++) {
  totalDebe += sumasSaldos[i].debeAcum;
  totalHaber += sumasSaldos[i].haberAcum;
  if (sumasSaldos[i].estado === 'crit') critCount++;
  else if (sumasSaldos[i].estado === 'warn') warnCount++;
}

// Alertas
var alertas = [];
for (var i = 0; i < sumasSaldos.length; i++) {
  var r = sumasSaldos[i];
  if (r.estado === 'crit') {
    alertas.push({ type: 'critical', title: 'Critica: ' + r.cuenta, desc: 'Saldo: $' + r.saldo.toLocaleString('es-AR') + ' | ' + r.codigo });
  } else if (r.estado === 'warn') {
    alertas.push({ type: 'warning', title: 'Atencion: ' + r.cuenta, desc: 'Saldo: $' + r.saldo.toLocaleString('es-AR') + ' supera umbral' });
  }
}

var evolucion = buildEvolucion(sumasSaldos);

msg.payload = {
  sumasSaldos: sumasSaldos,
  mayor: [], libroDiario: [], imputaciones: [],
  egresos: [], ingresos: [],
  proveedoresSaldos: [], proveedoresPendientes: [], interempresas: [],
  evolucion: evolucion,
  alertas: alertas,
  _metadata: {
    uuid: trace.uuid || 'N/A',
    source: 'gsheet',
    startDate: startDate,
    endDate: endDate,
    totalCuentas: sumasSaldos.length,
    totalDebe: totalDebe,
    totalHaber: totalHaber,
    saldoTotal: totalDebe - totalHaber,
    cuentasCriticas: critCount,
    cuentasAdvertencia: warnCount,
    timestamp: new Date().toISOString()
  }
};

return msg;

function buildEmptyResponse(sd, ed, uid, msg) {
  return {
    sumasSaldos: [],
    mayor: [], libroDiario: [], imputaciones: [],
    egresos: [], ingresos: [],
    proveedoresSaldos: [], proveedoresPendientes: [], interempresas: [],
    evolucion: { labels: [], caja: [], ventas: [], costos: [] },
    alertas: [{ type: 'info', title: 'Sin datos', desc: msg || 'No hay registros' }],
    _metadata: {
      uuid: uid || 'N/A', source: 'gsheet',
      startDate: sd, endDate: ed,
      totalCuentas: 0, totalDebe: 0, totalHaber: 0, saldoTotal: 0,
      cuentasCriticas: 0, cuentasAdvertencia: 0,
      timestamp: new Date().toISOString()
    }
  };
}

function buildEvolucion(accounts) {
  var grupos = {};
  var nombres = { '0': 'Activo', '1': 'Activo', '2': 'Pasivo', '3': 'Patrimonio', '4': 'Ingresos', '5': 'Egresos' };
  for (var i = 0; i < accounts.length; i++) {
    var prefijo = (accounts[i].codigo || '0').charAt(0);
    var name = nombres[prefijo] || 'Otros';
    grupos[name] = (grupos[name] || 0) + Math.abs(accounts[i].saldo);
  }
  var labels = Object.keys(grupos);
  var values = labels.map(function(k) { return grupos[k]; });
  if (labels.length === 0) { return { labels: ['Sin datos'], caja: [0], ventas: [0], costos: [0] }; }
  return { labels: labels, caja: values, ventas: [], costos: [] };
}

msg.payload = {
  status: 'ok',
  service: 'sumas-y-saldos',
  version: '3.0.0',
  architecture: 'dashboard-via-google-sheets',
  endpoints: { api: '/api/sumas-saldos?startDate=YYYYMMDD&endDate=YYYYMMDD', movimientos: '/api/sumas-saldos/movimientos?codigo=XXXXX', dashboard: '/sumas-saldos', health: '/api/sumas-saldos/health' },
  datasource: { sumasSaldos: 'Google Sheets (sync diario 06:00)', movimientos: 'MSSQL CORONA (directo)' },
  timestamp: new Date().toISOString()
};
return msg;

var codigo = (msg.req && msg.req.query && msg.req.query.codigo || '').toString().trim();

if (!codigo) {
  msg.statusCode = 400;
  msg.payload = { error: 'Parametro codigo es obligatorio' };
  return msg;
}

msg._codigo = codigo;
node.warn('[SumasSaldos-v3] Movimientos cuenta: ' + codigo + ' (desde Google Sheets)');
return msg;

// Sheet Movimientos: [0]CODIGO [1]CUENTA [2]FECHA [3]ASIENTO [4]DESCRIPCION [5]PROVEEDOR [6]ITEM [7]DEBE [8]HABER [9]SALDO [10]SYNC_UUID [11]UNIDAD_NEGOCIO(col I en sync)
if (msg.statusCode >= 400) { return msg; }

var rows = msg.payload;
var codigo = msg._codigo || '';

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  msg.payload = { success: true, cuenta: codigo, movimientos: [], total: 0, totalDebe: 0, totalHaber: 0, saldoTotal: 0, nota: 'Sin movimientos en el sheet' };
  return msg;
}

var movimientos = [];
var totalDebe = 0, totalHaber = 0;
for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  if (!Array.isArray(r) || r.length < 10) continue;
  if (String(r[0] || '').trim() !== codigo) continue;

  var debe = parseFloat(r[7]) || 0;
  var haber = parseFloat(r[8]) || 0;
  totalDebe += debe;
  totalHaber += haber;
  movimientos.push({
    fecha: r[2] || '',
    asiento: r[3] || '',
    descripcion: r[4] || '',
    proveedor: r[5] || '',
    item: r[6] || '',
    debe: debe,
    haber: haber,
    saldo: parseFloat(r[9]) || (debe - haber),
    unidad: String(r[11] || '').trim()
  });
}

msg.payload = {
  success: true,
  cuenta: codigo,
  movimientos: movimientos,
  total: movimientos.length,
  totalDebe: totalDebe,
  totalHaber: totalHaber,
  saldoTotal: totalDebe - totalHaber
};

return msg;

var codigo = (msg.req && msg.req.query && msg.req.query.codigo || '').toString().trim();

if (!codigo) {
  msg.statusCode = 400;
  msg.payload = { error: 'Parametro codigo es obligatorio' };
  return msg;
}

msg._codigo = codigo;
node.warn('[SumasSaldos-v3] Mayor cuenta: ' + codigo + ' (desde Google Sheets)');
return msg;

// Sheet: [0]CODIGO [1]CUENTA [2]FECHA [3]ASIENTO [4]DESCRIPCION [5]PROVEEDOR [6]ITEM [7]DEBE [8]HABER [9]SALDO [10]SYNC_UUID [11]UNIDAD_NEGOCIO(col I en sync)
// Ordenar por FECHA ASC para calcular saldo acumulado
if (msg.statusCode >= 400) { return msg; }

var rows = msg.payload;
var codigo = msg._codigo || '';

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  msg.payload = { success: true, cuenta: codigo, movimientos: [], total: 0, totalDebe: 0, totalHaber: 0, saldoAcumulado: 0 };
  return msg;
}

// Filtrar por CODIGO
var filtrados = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  if (!Array.isArray(r) || r.length < 10) continue;
  if (String(r[0] || '').trim() !== codigo) continue;

  filtrados.push({
    fecha: r[2] || '',
    asiento: r[3] || '',
    descripcion: r[4] || '',
    proveedor: r[5] || '',
    debe: parseFloat(r[7]) || 0,
    haber: parseFloat(r[8]) || 0,
    unidad: String(r[11] || '').trim()
  });
}

// Ordenar por FECHA ASC para running balance
filtrados.sort(function(a, b) { return (a.fecha || '').localeCompare(b.fecha || ''); });

// Calcular saldo acumulado (ASC) y luego invertir para mostrar mas reciente primero
var saldoAcc = 0;
var totalDebe = 0, totalHaber = 0;
for (var j = 0; j < filtrados.length; j++) {
  totalDebe += filtrados[j].debe;
  totalHaber += filtrados[j].haber;
  saldoAcc += filtrados[j].debe - filtrados[j].haber;
  filtrados[j].saldo = saldoAcc;
}
// Invertir: mas reciente primero
filtrados.reverse();

msg.payload = {
  success: true,
  cuenta: codigo,
  movimientos: filtrados,
  total: filtrados.length,
  totalDebe: totalDebe,
  totalHaber: totalHaber,
  saldoAcumulado: saldoAcc
};

return msg;

var startDate = (msg.req && msg.req.query && msg.req.query.startDate || '').toString().trim();
var endDate = (msg.req && msg.req.query && msg.req.query.endDate || '').toString().trim();

if (!startDate || !endDate) {
  var now = new Date();
  var y = now.getFullYear();
  var m = String(now.getMonth() + 1).padStart(2, '0');
  var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();
  startDate = y + m + '01';
  endDate = y + m + String(lastDay).padStart(2, '0');
}

msg._startDate = startDate;
msg._endDate = endDate;

node.warn('[SumasSaldos-v3] Caja periodo ' + startDate + '-' + endDate);
return msg;

// Sheet: [0]CODIGO [1]CUENTA [2]FECHA [3]ASIENTO [4]DESCRIPCION [5]PROVEEDOR [6]ITEM [7]DEBE [8]HABER [9]SALDO [10]SYNC_UUID [11]UNIDAD_NEGOCIO(col I en sync)
// Filtrar cuentas de caja/bancos: CODIGO que empieza con '01.01.01'
// Agrupar por FECHA para evolucion diaria

var rows = msg.payload;
var startDate = msg._startDate || '';
var endDate = msg._endDate || '';

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  msg.payload = { ingresos: [], egresos: [], diario: [], totalIngresos: 0, totalEgresos: 0, neto: 0 };
  return msg;
}

var ingresos = [];
var egresos = [];
var diario = {}; // fecha -> {ingresos, egresos}
var totalIngresos = 0;
var totalEgresos = 0;

for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  if (!Array.isArray(r) || r.length < 10) continue;
  var codigo = String(r[0] || '').trim();

  // Filtrar solo cuentas de caja y bancos
  if (codigo.indexOf('01.01.01') !== 0) continue;

  var fecha = (r[2] || '').toString().trim();
  var cuenta = (r[1] || '').toString().trim();
  var descripcion = (r[4] || '').toString().trim();
  var proveedor = (r[5] || '').toString().trim();
  var debe = parseFloat(r[7]) || 0;
  var haber = parseFloat(r[8]) || 0;

  // Filtrar por rango de fechas
  if (startDate && fecha < startDate) continue;
  if (endDate && fecha > endDate) continue;

  var mov = {
    fecha: fecha,
    cuenta: cuenta,
    codigo: codigo,
    descripcion: descripcion,
    proveedor: proveedor,
    debe: debe,
    haber: haber,
    unidad: String(r[11] || '').trim()
  };

  if (debe > 0) {
    ingresos.push(mov);
    totalIngresos += debe;
  }
  if (haber > 0) {
    egresos.push(mov);
    totalEgresos += haber;
  }

  // Agrupar por fecha para grafico
  if (!diario[fecha]) diario[fecha] = { ingresos: 0, egresos: 0 };
  diario[fecha].ingresos += debe;
  diario[fecha].egresos += haber;
}

// Ordenar movimientos por fecha DESC
ingresos.sort(function(a,b){ return b.fecha.localeCompare(a.fecha); });
egresos.sort(function(a,b){ return b.fecha.localeCompare(a.fecha); });

// Convertir diario a array ordenado
var fechas = Object.keys(diario).sort();
var diarioArr = fechas.map(function(f) {
  return { fecha: f, ingresos: diario[f].ingresos, egresos: diario[f].egresos, neto: diario[f].ingresos - diario[f].egresos };
});

msg.payload = {
  success: true,
  ingresos: ingresos.slice(0, 200),
  egresos: egresos.slice(0, 200),
  diario: diarioArr,
  totalIngresos: totalIngresos,
  totalEgresos: totalEgresos,
  neto: totalIngresos - totalEgresos,
  totalMovs: ingresos.length + egresos.length
};

return msg;
